# Check encoding and show Chest.cs and Item.cs with different encodings
for filepath in [
    '/mnt/Main/Git Projects/unity-templates/Templates/Assets/InventorySystem/Runtime/Chest.cs',
    '/mnt/Main/Git Projects/unity-templates/Templates/Assets/InventorySystem/Runtime/Item.cs',
]:
    print\(f'\\n=== {filepath.split\("/"\)[-1]} ==='\)
    for enc in ['utf-8', 'utf-8-sig', 'cp1251']:
        try:
            with open\(filepath, 'r', encoding=enc\) as f:
                content = f.read\(\)
            cyrillic_lines = [\(i+1, l.rstrip\(\)\) for i, l in enumerate\(content.splitlines\(\)\) if any\('\\u0400' <= c <= '\\u04ff' or c == '\\ufffd' for c in l\)]
            if cyrillic_lines:
                print\(f'  [{enc}] Found cyrillic/replacement chars:'\)
                for num, line in cyrillic_lines:
                    print\(f'    Line {num}: {line}'\)
            else:
                print\(f'  [{enc}] No cyrillic found'\)
            break
        except Exception as e:
            print\(f'  [{enc}] Error: {e}'\)
EOF)
